from functools import lru_cache
class Solution:
    def stoneGameVI(self, aliceValues, bobValues):
        n = len(aliceValues)

        @lru_cache(maxsize=None)
        def solve(mask):
            if mask == (1 << n) - 1:
                return 0
            picked = bin(mask).count('1')
            alice_turn = picked % 2 == 0
            best = None
            for i in range(n):
                if mask & (1 << i):
                    continue
                gain = aliceValues[i] if alice_turn else -bobValues[i]
                val = gain + solve(mask | (1 << i))
                if best is None:
                    best = val
                elif alice_turn and val > best:
                    best = val
                elif not alice_turn and val < best:
                    best = val
            return best

        diff = solve(0)
        if diff > 0:
            return 1
        if diff < 0:
            return -1
        return 0

