class Solution:
    def stoneGameVI(self, aliceValues, bobValues):
        n = len(aliceValues)
        order = sorted(range(n), key=lambda i: -(aliceValues[i] + bobValues[i]))
        alice = bob = 0
        for turn, i in enumerate(order):
            if turn % 2 == 0:
                alice += aliceValues[i]
            else:
                bob += bobValues[i]
        if alice > bob:
            return 1
        if alice < bob:
            return -1
        return 0

